134→/* General visitor class for performing interpretation; defines ComASTVistor methods which are common to SymAST and SDAST representations. */
135→abstract class Evaluator<Env extends Environment> implements EvalVisitor {
136→  
137→  /* Assumes that:
138→   *   OpTokens are unique
139→   *   Only objects used as boolean values are BoolConstant.TRUE and BoolConstant.FALSE
140→   * Hence,  == can be used to compare OpTokens, and BoolConstants.
141→   */
142→  
143→  Env env;  // getter defined below
144→  
145→  /* Constructor */
146→  Evaluator(Env e) { env = e; }
147→  
148→  private JamVal[] evalArgs(AST[] args) {
149→    int n = args.length;
150→    JamVal[] vals = new JamVal[n];
151→    for (int i = 0; i < n; i++) vals[i] = args[i].accept(this);
152→    return vals;
153→  }
154→  
155→  /* EvalVisitor methods */
156→  
157→  /** Getter for env field */
158→  public Env env() { return env; }
159→  
160→  /* ASTVisitor methods.  EvalVisitor extends ASTVisitor<JamVal>. */
161→  public UnOpVisitor<JamVal> newUnOpVisitor(JamVal arg) { return new UnOpEvaluator(arg); } 
162→  public BinOpVisitor<JamVal> newBinOpVisitor(AST arg1, AST arg2) { return new BinOpEvaluator(arg1, arg2); }  
163→  public FunVisitor<JamVal> newFunVisitor(AST args[]) {  return new FunEvaluator(evalArgs(args)); }
164→  
165→  /* ComASTVisitor<JamVal> methods.  ASTVisitor<JamVal> extends ComASTVisitor<JamVal>. */
166→  
167→  /** Method for an aborting error, used in subclasses; package visibility */ 
168→  JamVal forDefault(AST a) { throw new EvalException(a + " is not in the domain of the visitor " + getClass()); }
169→  public JamVal forBoolConstant(BoolConstant b) { return b; }
170→  public JamVal forIntConstant(IntConstant i) { return i; }
171→  public JamVal forEmptyConstant(EmptyConstant n) { return JamEmpty.ONLY; }
172→  public JamVal forPrimFun(PrimFun f) { return f; }
173→  public JamVal forUnOpApp(UnOpApp u) { return u.rator().accept(newUnOpVisitor(u.arg().accept(this))); }
174→  public JamVal forBinOpApp(BinOpApp b) { return b.rator().accept(newBinOpVisitor(b.arg1(), b.arg2())); }
175→ 
176→  public JamVal forApp(App a) {
177→    JamVal rator = a.rator().accept(this);
178→    if (rator instanceof JamFun)  {
179→      //System.err.println(Evaluator.this);
180→      //System.err.println(newFunVisitor(a.args()).getClass());
181→      return ((JamFun) rator).accept(newFunVisitor(a.args()));
182→    }
183→    throw new EvalException(rator + " appears at head of application " + a  + " but it is not a valid function");
184→  }
185→  
186→  public JamVal forIf(If i) {
187→    JamVal test = i.test().accept(this);
188→    if (! (test instanceof BoolConstant))
189→      throw new EvalException("non Boolean " + test + " used as test in if");
190→    if (test == BoolConstant.TRUE) return i.conseq().accept(this);
191→    return i.alt().accept(this);
192→  }
193→
194→  public JamVal forBlock(Block b) {
195→    AST[] exps = b.exps();
196→    int n = exps.length;
197→    for (int i = 0; i < n-1; i++) exps[i].accept(this);
198→    return exps[n-1].accept(this);
199→  }
