   801→/** A Jam list */
   802→interface JamList extends PureList<JamVal>, JamVal {
   803→  JamEmpty empty();
   804→  JamCons cons(JamVal v);
   805→  String toStringHelp(int maxDepth);
   806→}
   807→
   808→class JamEmpty extends Empty<JamVal> implements JamList {
   809→  public static final JamEmpty ONLY = new JamEmpty();
   810→  private JamEmpty() {}
   811→  public JamEmpty empty() { return ONLY; }
   812→  public JamCons cons(JamVal v) { return new JamCons(v, this); }
   813→  public <RtnType> RtnType accept(JamValVisitor<RtnType> v) { return v.forJamList(this); }
   814→  public String toStringHelp(int maxDepth) { return ""; }
   815→}
   816→
   817→class JamCons extends Cons<JamVal> implements JamList {
   818→  private static final int MAX_DEPTH = 100;
   819→  public JamCons(JamVal f, JamList r) { super(f, r); }
   820→  public JamEmpty empty() { return JamEmpty.ONLY; }
   821→  public JamCons cons(JamVal v) { return new JamCons(v, this); }
   822→  
   823→  public <RtnType> RtnType accept(JamValVisitor<RtnType> v) { return v.forJamList(this); }
   824→  
   825→//  public JamVal first() { return first; }  // work-around for bridge method bug in compiler (since fixed)
   826→  public JamList rest() { return (JamList) rest; }
   827→  
   828→  public String toString() { return "(" + first() + rest().toStringHelp(MAX_DEPTH) + ")"; }
   829→  public String toStringHelp(int maxDepth) { 
   830→    if (maxDepth == 0) return " ...";
   831→    return " " + first() + rest().toStringHelp(maxDepth - 1); }
   832→}
