1982→  /** Reshapes the arguments and adds the continuation as the final argument */
1983→  private SymAST[] reshape(SymAST[] args, SymAST cont) {
1984→    int n = args.length;
1985→    SymAST[] newArgs = new SymAST[n+1];
1986→    for (int i = 0; i < n; i++) 
1987→      newArgs[i] = args[i].accept(reshape);
1988→    newArgs[n] = cont;
1989→    return newArgs;
