1992→  /* Convert exp,cont to correponding CPS'ed program */ 
1993→  public SymAST convertToCPS(SymAST exp, SymAST cont) {
1994→    if (exp.accept(isSimple)) 
1995→      return new App(cont, new SymAST[] { exp.accept(reshape) });  
1996→    return exp.accept(new ConvertToCPS(cont));
1997→  }
