1999→  /** Converts a non-simple expression to CPS form */
2000→  class ConvertToCPS implements SymASTVisitor<SymAST> {
2001→    
2002→    SymAST cont;
2003→    
2004→    ConvertToCPS(SymAST c) { cont = c; }
2005→

2005→    
2006→    /* None of the following block of methods should ever be executed if the host is not simple. */
2007→    public SymAST forIntConstant(IntConstant i) {  return new App(cont, new SymAST[] {i}); }
2008→    public SymAST forEmptyConstant(EmptyConstant n) { return new App(cont, new SymAST[] {n}); }
2009→    public SymAST forBoolConstant(BoolConstant b) { return new App(cont, new SymAST[] {b}); }
2010→    public SymAST forVariable(Variable v) { return new App(cont, new SymAST[] {v}); }
2011→    public SymAST forPrimFun(PrimFun f) { return new App(cont, new SymAST[] {f.accept(reshape)}); }
2012→    public SymAST forMap(Map m) { return new App(cont, new SymAST[] {m.accept(reshape)}); }
2013→    
2014→    public SymAST forUnOpApp(UnOpApp u) {
2015→      SymAST arg = (SymAST) u.arg();
2016→      Variable v1 = genVariable();
2017→      SymAST body = new UnOpApp(u.rator(), v1);
2018→      if (arg.accept(isSimple)) return new App(cont, new SymAST[] {u.accept(reshape)});
2019→      else return convertToCPS(new Let(new Def[] {new Def(v1, arg)}, body), cont);
2020→    }
2021→    
2022→    public SymAST forBinOpApp(BinOpApp b) {
2023→      SymAST arg1 = (SymAST) b.arg1();
2024→      SymAST arg2 = (SymAST) b.arg2();
2025→      Variable v1 = genVariable();
2026→      Variable v2 = genVariable();
2027→      SymAST body = new BinOpApp(b.rator(), v1, v2);
2028→      if (arg1.accept(isSimple) && arg2.accept(isSimple)) return new App(cont, new SymAST[] { b.accept(reshape) });
2029→      else return convertToCPS(new Let(new Def[] {new Def(v1, arg1), new Def(v2, arg2)}, body), cont); 
2030→    }
2031→    
2032→    public SymAST forApp(App a) {
2033→      
2034→      SymAST rator = (SymAST) a.rator();
2035→      SymAST[] args = (SymAST[]) a.args();
2036→      int n = args.length;
2037→      
2038→      /* Map is a special case of a simple expression  (Simplification not in the rules!) */
2039→      if (rator instanceof Map) {
2040→        Map m = (Map) rator;
2041→        Variable[] vars = m.vars();
2042→        if (vars.length != n) throw new CPSException("map `" + m + "' applied to only " + n + " arguments");
2043→        if (n == 0) return convertToCPS(m.body(), cont);
2044→        Def[] newDefs = new Def[n];
2045→        for (int i = 0; i < n; i++) newDefs[i] = new Def(vars[i], args[i]);
2046→        return convertToCPS(new Let(newDefs, m.body()), cont);
2047→      } 
2048→      
2049→      if (rator.accept(isSimple)) { 
2050→        boolean allArgsSimple = true;
2051→        for (int i = 0; i < n; i++) {
2052→          if (! args[i].accept(isSimple)) {
2053→            allArgsSimple = false;
2054→            break;
2055→          } 
2056→        }
2057→        
2058→        if (allArgsSimple)  { // all args only perform local allocation
2059→//          System.err.println("Simple Args are: " + ToString.toString(args, ","));
2060→          SymAST[] newArgs = reshape(args,cont);
2061→          return new App(rator.accept(reshape), newArgs);
2062→        }
2063→        
2064→        /* Some arguments are not simple. The rator is simple but not a map, and some argument is non-simple. */
2065→        Variable[] newVars = new Variable[n];
2066→        Def[] newDefs = new Def[n];
2067→        for (int i = 0; i < n; i++) {
2068→          Variable var = genVariable();
2069→          newVars[i] = var;
2070→          newDefs[i] = new Def(var, args[i]);
2071→        }
2072→        return convertToCPS(new Let(newDefs, new App(rator,newVars)), cont);
2073→      }
2074→      
2075→      /* The rator is not simple. */
2076→      Variable newVar = genVariable();
2077→//      return convertToCPS(new Let(new Def[] {new Def(newVar, rator)}, new App(newVar, args)), cont);
2078→
2079→      Variable[] newVars = new Variable[n];
2080→      Def[] newDefs = new Def[n+1];
2081→      for (int i = 0; i < n; i++) {
2082→        Variable var = genVariable();
2083→        newVars[i] = var;
2084→        newDefs[i+1] = new Def(var, args[i]);
2085→      }
2086→      newDefs[0] = new Def(newVar, rator);
2087→      return convertToCPS(new Let(newDefs, new App(newVar,newVars)), cont);
2088→    }
2089→       
2090→    public SymAST forIf(If i) {
2091→      SymAST test = (SymAST) i.test();
2092→      SymAST conseq = (SymAST) i.conseq();
2093→      SymAST alt = (SymAST) i.alt();
2094→      if (test.accept(isSimple))
2095→        return new If(test.accept(reshape), convertToCPS(conseq, cont), convertToCPS(alt, cont));
2096→      Variable newVar = genVariable();
2097→      return convertToCPS(new Let(new Def[] {new Def(newVar,test)}, new If(newVar,conseq,alt)), cont);
2098→    }
