2389→/* Class for converting a SymAST (symbol variables in AST) to an SDAST (static distance coordinates in AST) */
2390→class SConverter {
2391→    
2392→  SymbolTable symbolTable;
2393→  SymASTVisitor<SDAST> convert;   // visitor that performs the conversion
2394→  
2395→  SConverter() {
2396→    symbolTable = new SymbolTable();
