2402→  /** Visitor class for performing the static distance conversion.  Static distance conversion maps SymASTs to SDASTs;
2403→    * this bmodifies symbolTable during traversal, but restores it on exit */

2403→    * this bmodifies symbolTable during traversal, but restores it on exit */
2404→  class SConvert implements SymASTVisitor<SDAST> {
2405→    
2406→    int depth; // lexical depth of expression being visited
2407→    
2408→    SConvert(int d) { depth = d; }
2409→    
2410→    /** Returns SDPair containing (depth - [dist for v in symbolTable], offset for v in symbolTable).
2411→      * Note: programs are assumed to be well-formed. */ 
2412→    SDPair lookup(Variable v) {
2413→      SDPair match = (SDPair) symbolTable.get(v);
2414→      if (match == null) 
2415→        throw new SConvertException("Variable " + v + " not found in Symbol Table");
2416→      return new SDPair(depth - match.dist(), match.offset());
2417→    }
2418→  
2419→    public SDAST forIntConstant(IntConstant i) { return i; }
2420→    public SDAST forEmptyConstant(EmptyConstant n) { return n; }
2421→    public SDAST forBoolConstant(BoolConstant b) { return b; }
2422→    public SDAST forVariable(Variable v) { return lookup(v); }
2423→    public SDAST forPrimFun(PrimFun f) { return f; }
2424→    
2425→    public SDAST forUnOpApp(UnOpApp u) { 
2426→      SymAST arg = (SymAST) u.arg();
2427→      return new UnOpApp(u.rator(), arg.accept(this));
2428→    }
2429→    
2430→    public SDAST forBinOpApp(BinOpApp b) {
2431→      SymAST arg1 = (SymAST) b.arg1();
2432→      SymAST arg2 = (SymAST) b.arg2(); 
2433→      return new BinOpApp(b.rator(), arg1.accept(this), arg2.accept(this));
2434→    }
2435→    
2436→    public SDAST forApp(App a) {
2437→      SymAST rator = (SymAST) a.rator();
2438→      SymAST[] args = (SymAST[]) a.args();
2439→      int n = args.length;
2440→      SDAST[] newArgs = new SDAST[n];
2441→      for (int i = 0; i < n; i++) newArgs[i] = args[i].accept(this);
2442→      return new App(rator.accept(this), newArgs);
2443→    }
2444→    
2445→    public SDAST forMap(Map m) { 
2446→      //System.out.println("forMap:" + m + " depth: " + depth);
2447→
2448→      Variable[] vars = m.vars();
2449→      int n = vars.length;
2450→      for (int i = 0; i < n; i++) symbolTable.put(vars[i], new SDPair(depth+1,i));
2451→      SDAST result =  new SMap(n, m.body().accept(new SConvert(depth+1)));
2452→      for (int i = 0; i < n; i++) symbolTable.remove(vars[i]);
2453→      return result;
2454→    }
