2456→    public SDAST forIf(If i) {
2457→      SymAST test = (SymAST) i.test();
2458→      SymAST conseq = (SymAST) i.conseq();
2459→      SymAST alt = (SymAST) i.alt();
2460→      return new If(test.accept(this), conseq.accept(this), alt.accept(this));
2461→    }
