2463→    public SDAST forLet(Let l) {
2464→      Def[] defs = l.defs();
2465→      int n = defs.length;
2466→      SDAST[] newRhs = new SDAST[n];
2467→      for (int i = 0; i < n; i++) newRhs[i] = defs[i].rhs().accept(this);
2468→      for (int i = 0; i < n; i++) symbolTable.put(l.defs()[i].lhs(), new SDPair(depth+1,i));
2469→      SDAST result = new SLet(newRhs, l.body().accept(new SConvert(depth+1)));
2470→      for (int i = 0; i < n; i++) symbolTable.remove(defs[i].lhs());
2471→      return result;
2472→    }
