2474→    public SDAST forLetRec(LetRec l) {
2475→      Def[] defs = l.defs();
2476→      int n = defs.length;
2477→      for (int i = 0; i < n; i++) symbolTable.put(l.defs()[i].lhs(), new SDPair(depth+1,i));
2478→      SymASTVisitor<SDAST> newSC = new SConvert(depth+1);
2479→      SDAST[] newRhs = new SDAST[n];
2480→      for (int i = 0; i < n; i++) newRhs[i] = defs[i].rhs().accept(newSC);
2481→      SDAST result = new SLetRec(newRhs, l.body().accept(newSC));
2482→      for (int i = 0; i < n; i++) symbolTable.remove(defs[i].lhs());
2483→      return result;
2484→    }
