2497→  static class SymbolTable {    
2498→    /* Table mapping variables to LinkedLists of SDPair (depth,offset) */
2499→    HashMap<Variable,LinkedList<SDPair>> table = new HashMap<Variable,LinkedList<SDPair>>();  
2500→    
2501→    SDPair get(Variable v) {
2502→      LinkedList<SDPair> vStack = table.get(v);
2503→      if (v == null) return null;
2504→      return (SDPair) vStack.getLast();
2505→    }
2506→    
2507→    void put(Variable v, SDPair p) {
2508→      LinkedList<SDPair> vStack = table.get(v);
2509→      if (vStack == null) {
2510→        vStack = new LinkedList<SDPair>();
2511→        table.put(v,vStack);
2512→      }
2513→      vStack.addLast(p);
2514→    }
2515→    
2516→    void remove(Variable v) {
2517→      LinkedList<SDPair> vStack = table.get(v);
2518→      if (vStack == null) throw new SConvertException("Variable " + v + " not available in symbol table to delete");
2519→      vStack.removeLast();
2520→    }
2521→  }
2522→}
